@if (!IsVisible)
{
    <button class="btn btn-outline-primary btn-sm w-100" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="card mt-2">
        <div class="card-body p-2">
            <div class="mb-2">
                <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="title" />
            </div>
            <div class="mb-2">
                <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="assignee" />
            </div>
            <div class="mb-2">
                <select class="form-select form-select-sm" @bind="priority">
                    <option value="High">High</option>
                    <option value="Medium">Medium</option>
                    <option value="Low">Low</option>
                </select>
            </div>
            <div class="mb-2">
                <input type="date" class="form-control form-control-sm" @bind="dueDate" />
            </div>
            <div class="d-flex gap-1">
                <button class="btn btn-primary btn-sm" @onclick="Save">Save</button>
                <button class="btn btn-secondary btn-sm" @onclick="Cancel">Cancel</button>
            </div>
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskCreated { get; set; }

    private bool IsVisible;
    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        IsVisible = false;
        ResetForm();
    }

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(title)) return;
        await OnTaskCreated.InvokeAsync((title, assignee, priority, dueDate));
        IsVisible = false;
        ResetForm();
    }

    private void ResetForm()
    {
        title = "";
        assignee = "";
        priority = "Medium";
        dueDate = DateTime.Today.AddDays(7);
    }
}

@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-link" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="allTasks" />
    <BoardSearchBar @bind-SearchText="searchText" />

    <div class="row g-3">
        @for (int i = 0; i < columns.Length; i++)
        {
            var colIndex = i;
            var colName = columns[colIndex];
            <BoardColumn ColumnName="@colName"
                         ColumnIndex="colIndex"
                         Tasks="GetFilteredTasks(colName)"
                         OnMoveLeft="HandleMoveLeft"
                         OnMoveRight="HandleMoveRight"
                         OnTaskCreated="args => HandleAddTask(colName, args)" />
        }
    </div>
}

@code {
    private static readonly string[] columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = [];
    private string searchText = "";
    private bool loading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        try
        {
            loading = true;
            errorMessage = null;
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var filtered = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            filtered = filtered.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return filtered.ToList();
    }

    private async Task HandleMoveLeft(TaskItem task)
    {
        var currentIndex = Array.IndexOf(columns, task.Status);
        if (currentIndex > 0)
        {
            var newStatus = columns[currentIndex - 1];
            await MoveTask(task, newStatus);
        }
    }

    private async Task HandleMoveRight(TaskItem task)
    {
        var currentIndex = Array.IndexOf(columns, task.Status);
        if (currentIndex < columns.Length - 1)
        {
            var newStatus = columns[currentIndex + 1];
            await MoveTask(task, newStatus);
        }
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleAddTask(string status, (string Title, string Assignee, string Priority, DateTime DueDate) args)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            allTasks.Add(newTask);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

